	DeletedAt *int64 `json:"deleted_at,omitempty" example:"1672531200"`
}

// UserRepository 用户存储接口
type UserRepository interface {
	Create(user *User) error
	GetByID(id int64) (*User, error)
	GetAll() ([]*User, error)
	Update(id int64, user *User) error
	Delete(id int64) error
}

// MemoryUserRepository 内存用户存储实现
type MemoryUserRepository struct {
	users map[int64]*User
	mu    sync.RWMutex
	nextID int64
}

// NewMemoryUserRepository 创建内存用户存储实例
func NewMemoryUserRepository() *MemoryUserRepository {
	return &MemoryUserRepository{
		users:  make(map[int64]*User),
		nextID: 1,
	}
}

// Create 创建用户
func (r *MemoryUserRepository) Create(user *User) error {
	r.mu.Lock()
	defer r.mu.Unlock()

	// 检查邮箱是否已存在
	for _, u := range r.users {
		if u.Email == user.Email && u.DeletedAt == nil {
			return fmt.Errorf("email already exists: %s", user.Email)
		}
	}

	now := int64(1672531200) // 简化时间处理，实际应该用 time.Now().Unix()
	user.ID = r.nextID
	user.CreatedAt = now
	user.UpdatedAt = now
	user.DeletedAt = nil

	r.users[user.ID] = user
	r.nextID++
	return nil
}

// GetByID 根据ID获取用户
func (r *MemoryUserRepository) GetByID(id int64) (*User, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	user, exists := r.users[id]
	if !exists || user.DeletedAt != nil {
		return nil, fmt.Errorf("user not found: %d", id)
	}
	return user, nil
}

// GetAll 获取所有用户
func (r *MemoryUserRepository) GetAll() ([]*User, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	var result []*User
	for _, user := range r.users {
		if user.DeletedAt == nil {
			result = append(result, user)
		}
	}
	return result, nil
}

// Update 更新用户
func (r *MemoryUserRepository) Update(id int64, user *User) error {
	r.mu.Lock()
	defer r.mu.Unlock()

	existing, exists := r.users[id]
	if !exists || existing.DeletedAt != nil {
		return fmt.Errorf("user not found: %d", id)
	}

	// 检查邮箱是否被其他用户使用
	for _, u := range r.users {
		if u.ID != id && u.Email == user.Email && u.DeletedAt == nil {
			return fmt.Errorf("email already exists: %s", user.Email)
		}
	}

	now := int64(1672531200) // 简化时间处理
	user.ID = id
	user.CreatedAt = existing.CreatedAt
	user.UpdatedAt = now
	user.DeletedAt = existing.DeletedAt

	r.users[id] = user
	return nil
}

// Delete 删除用户（软删除）
func (r *MemoryUserRepository) Delete(id int64) error {
	r.mu.Lock()
	defer r.mu.Unlock()

	user, exists := r.users[id]
	if !exists || user.DeletedAt != nil {
		return fmt.Errorf("user not found: %d", id)
	}

	now := int64(1672531200) // 简化时间处理
	user.DeletedAt = &now
	return nil
}

