    "internal/repository/user_repository.go": "package repository

import (
	"errors"
	"sync"

	"user-api/internal/model"
)

var (
	// ErrUserNotFound 用户不存在错误
	ErrUserNotFound = errors.New("user not found")
	// ErrUserAlreadyExists 用户已存在错误
	ErrUserAlreadyExists = errors.New("user already exists")
)

// UserRepository 用户存储接口
type UserRepository interface {
	Create(user *model.User) error
	GetByID(id string) (*model.User, error)
	GetAll() ([]*model.User, error)
	Update(id string, user *model.User) error
	Delete(id string) error
}

// userRepository 用户存储实现（内存存储）
type userRepository struct {
	mu    sync.RWMutex
	users map[string]*model.User
}

// NewUserRepository 创建新的用户存储实例
func NewUserRepository() UserRepository {
	return &userRepository{
		users: make(map[string]*model.User),
	}
}

// Create 创建用户
func (r *userRepository) Create(user *model.User) error {
	r.mu.Lock()
	defer r.mu.Unlock()

	// 检查用户是否已存在
	for _, u := range r.users {
		if u.Email == user.Email {
			return ErrUserAlreadyExists
		}
	}

	r.users[user.ID] = user
	return nil
}

// GetByID 根据ID获取用户
func (r *userRepository) GetByID(id string) (*model.User, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	user, exists := r.users[id]
	if !exists {
		return nil, ErrUserNotFound
	}

	return user, nil
}

// GetAll 获取所有用户
func (r *userRepository) GetAll() ([]*model.User, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	users := make([]*model.User, 0, len(r.users))
	for _, user := range r.users {
		users = append(users, user)
	}

	return users, nil
}

// Update 更新用户
func (r *userRepository) Update(id string, updatedUser *model.User) error {
	r.mu.Lock()
	defer r.mu.Unlock()

	user, exists := r.users[id]
	if !exists {
		return ErrUserNotFound
	}

	// 检查邮箱是否被其他用户使用
	for uid, u := range r.users {
		if u.Email == updatedUser.Email && uid != id {
			return ErrUserAlreadyExists
		}
	}

	// 更新用户信息
	user.Name = updatedUser.Name
	user.Email = updatedUser.Email
	user.Age = updatedUser.Age
	user.UpdatedAt = updatedUser.UpdatedAt

	r.users[id] = user
	return nil
}

// Delete 删除用户
func (r *userRepository) Delete(id string) error {
	r.mu.Lock()
	defer r.mu.Unlock()

	if _, exists := r.users[id]; !exists {
		return ErrUserNotFound
	}

	delete(r.users, id)
	return nil
}
